/**
 * @summary Upload a file attachment to a request
 */
export const getUploadRequestFileUrl = (id: number) => {
  return `/api/requests/${id}/files`;
};

export const uploadRequestFile = async (
  id: number,
  uploadRequestFileBody: UploadRequestFileBody,
  options?: RequestInit,
): Promise<UploadedFile> => {
  const formData = new FormData();
  if (uploadRequestFileBody.file !== undefined) {
    formData.append(`file`, uploadRequestFileBody.file);
  }
  if (uploadRequestFileBody.description !== undefined) {
    formData.append(`description`, uploadRequestFileBody.description);
  }

  return customFetch<UploadedFile>(getUploadRequestFileUrl(id), {
    ...options,
    method: "POST",
    body: formData,
  });
};

